import React from 'react';
import * as C from './style'

function UseForm() {
    return (
        <C.Container>
            <C.Label for>Nome</C.Label>
            <C.Input name='nome' id='nome'/>
            <C.Label for>Endereço</C.Label>
            <C.Input name='nome' id='nome'/>
            <C.Label for>Telefone</C.Label>
            <C.Input name='nome' id='nome'/>
        </C.Container>
    )
}

export default UseForm
